/**
 * alpha-jump.test.ts — Death #4 live-mode gate (`shouldSkipCanonicalHop`)
 * truth-table coverage + `dispatchSeedHttp` end-to-end fetch surface.
 *
 * Why these tests:
 * - The receiver (`apps/worker-node1/src/residual-seed-handler.ts`) emits
 *   an ack with `shadow_mode`, `fully_resolved`, and (live + partial only)
 *   `awaiting_resolution`. Today no caller consults the ack — these tests
 *   fence the gate behavior so when callers are wired up they cannot
 *   silently regress to "always canonical" or "always Fano".
 * - The substrate-level guarantee from OCTONION_ROUTING_PLAN.md §5 ("the
 *   floor is no worse than today") rides on every pathological ack shape
 *   degrading to `false`. Bad acks must NOT silently authorize the skip.
 */

import { describe, expect, it } from 'vitest';

import {
  AlphaJumpDispatcher,
  FanoLine,
  shouldSkipCanonicalHop,
  type ResidualSeedAck,
} from '../src/alpha-jump';
import type { FlowTransport } from '@a0n/aeon/flow';

// ── shouldSkipCanonicalHop — pure gate truth table ───────────────────────

describe('shouldSkipCanonicalHop', () => {
  it('shadow_mode_response_does_not_skip_canonical (default behavior unchanged)', () => {
    // Shadow mode: receiver omits awaiting_resolution; canonical always wins.
    const shadowFull: ResidualSeedAck = { shadow_mode: true, fully_resolved: true };
    const shadowPartial: ResidualSeedAck = { shadow_mode: true, fully_resolved: false };
    expect(shouldSkipCanonicalHop(shadowFull)).toBe(false);
    expect(shouldSkipCanonicalHop(shadowPartial)).toBe(false);
  });

  it('live_mode_full_bitset_skips_canonical (the new path)', () => {
    // Live + fully resolved + awaiting_resolution absent — Fano sum substitutes.
    const liveFull: ResidualSeedAck = { shadow_mode: false, fully_resolved: true };
    expect(shouldSkipCanonicalHop(liveFull)).toBe(true);
  });

  it('live_mode_partial_bitset_falls_back_to_canonical (safety)', () => {
    // Live + partial: receiver sets awaiting_resolution=true. Wait it out.
    const livePartial: ResidualSeedAck = {
      shadow_mode: false,
      fully_resolved: false,
      awaiting_resolution: true,
    };
    expect(shouldSkipCanonicalHop(livePartial)).toBe(false);
  });

  it('contradictory ack (live + full + awaiting=true) degrades to canonical', () => {
    // Race condition / receiver bug: bitset went from full back to partial
    // mid-stream. Trust the canonical chain, not the optimistic flag.
    const contradictory: ResidualSeedAck = {
      shadow_mode: false,
      fully_resolved: true,
      awaiting_resolution: true,
    };
    expect(shouldSkipCanonicalHop(contradictory)).toBe(false);
  });

  it('null / undefined / non-object ack degrades to canonical', () => {
    expect(shouldSkipCanonicalHop(null)).toBe(false);
    expect(shouldSkipCanonicalHop(undefined)).toBe(false);
    // Cast through `unknown` to feed a non-object — the gate guards this.
    expect(shouldSkipCanonicalHop('oops' as unknown as ResidualSeedAck)).toBe(false);
    expect(shouldSkipCanonicalHop(42 as unknown as ResidualSeedAck)).toBe(false);
  });

  it('missing required fields degrade to canonical', () => {
    expect(shouldSkipCanonicalHop({} as ResidualSeedAck)).toBe(false);
    expect(
      shouldSkipCanonicalHop({ shadow_mode: false } as ResidualSeedAck),
    ).toBe(false);
    expect(
      shouldSkipCanonicalHop({ fully_resolved: true } as ResidualSeedAck),
    ).toBe(false);
  });
});

// ── dispatchSeedHttp — fetch surface + gate integration ──────────────────

/** Minimal in-memory transport — `dispatchSeedHttp` ignores the WS path
 *  but the dispatcher constructor still requires one. */
function makeNoopTransport(): FlowTransport {
  return {
    send: () => {},
    onReceive: () => {},
    close: () => {},
  };
}

function makeDispatcher(opts?: { shadow?: boolean }): AlphaJumpDispatcher {
  return new AlphaJumpDispatcher(makeNoopTransport(), {
    shadow: opts?.shadow ?? false,
  });
}

function basicFrameOpts() {
  return {
    line: FanoLine.E1_E4_E5,
    sign: 'pos' as const,
    payload: new Float32Array([0.1, 0.2, 0.3, 0.4]),
    srcLayer: 0,
    dstLayer: 1,
    tokenSeq: 42,
    dstWorkerUrl: 'https://test-worker.example.com',
  };
}

describe('AlphaJumpDispatcher.dispatchSeedHttp', () => {
  it('parses a live + fully-resolved ack and authorizes the skip', async () => {
    const dispatcher = makeDispatcher();
    const fetchImpl = async () =>
      new Response(
        JSON.stringify({ shadow_mode: false, fully_resolved: true, ack: true }),
        { status: 200, headers: { 'Content-Type': 'application/json' } },
      );
    const { ack, skipCanonical } = await dispatcher.dispatchSeedHttp(
      basicFrameOpts(),
      fetchImpl as unknown as typeof fetch,
    );
    expect(ack?.fully_resolved).toBe(true);
    expect(skipCanonical).toBe(true);
  });

  it('parses a live + partial ack and refuses the skip', async () => {
    const dispatcher = makeDispatcher();
    const fetchImpl = async () =>
      new Response(
        JSON.stringify({
          shadow_mode: false,
          fully_resolved: false,
          awaiting_resolution: true,
          ack: true,
        }),
        { status: 200, headers: { 'Content-Type': 'application/json' } },
      );
    const { ack, skipCanonical } = await dispatcher.dispatchSeedHttp(
      basicFrameOpts(),
      fetchImpl as unknown as typeof fetch,
    );
    expect(ack?.awaiting_resolution).toBe(true);
    expect(skipCanonical).toBe(false);
  });

  it('shadow-mode ack always refuses the skip', async () => {
    const dispatcher = makeDispatcher({ shadow: true });
    const fetchImpl = async () =>
      new Response(
        JSON.stringify({ shadow_mode: true, fully_resolved: true, ack: true }),
        { status: 200, headers: { 'Content-Type': 'application/json' } },
      );
    const { ack, skipCanonical } = await dispatcher.dispatchSeedHttp(
      basicFrameOpts(),
      fetchImpl as unknown as typeof fetch,
    );
    expect(ack?.shadow_mode).toBe(true);
    expect(skipCanonical).toBe(false);
  });

  it('non-2xx response degrades to skipCanonical=false', async () => {
    const dispatcher = makeDispatcher();
    const fetchImpl = async () =>
      new Response('boom', { status: 500 });
    const { ack, skipCanonical } = await dispatcher.dispatchSeedHttp(
      basicFrameOpts(),
      fetchImpl as unknown as typeof fetch,
    );
    expect(ack).toBeNull();
    expect(skipCanonical).toBe(false);
  });

  it('network error / thrown fetch degrades to skipCanonical=false', async () => {
    const dispatcher = makeDispatcher();
    const fetchImpl = async () => {
      throw new Error('ECONNREFUSED');
    };
    const { ack, skipCanonical } = await dispatcher.dispatchSeedHttp(
      basicFrameOpts(),
      fetchImpl as unknown as typeof fetch,
    );
    expect(ack).toBeNull();
    expect(skipCanonical).toBe(false);
  });

  it('non-JSON 200 body degrades to skipCanonical=false', async () => {
    const dispatcher = makeDispatcher();
    const fetchImpl = async () => new Response('not json', { status: 200 });
    const { ack, skipCanonical } = await dispatcher.dispatchSeedHttp(
      basicFrameOpts(),
      fetchImpl as unknown as typeof fetch,
    );
    expect(ack).toBeNull();
    expect(skipCanonical).toBe(false);
  });

  it('POSTs to {dstWorkerUrl}/residual-seed with the encoded frame as body', async () => {
    const dispatcher = makeDispatcher();
    const seenUrls: string[] = [];
    let seenMethod: string | undefined;
    let seenContentType: string | null = null;
    let seenBodyBytes = 0;

    const fetchImpl = async (url: RequestInfo | URL, init?: RequestInit) => {
      seenUrls.push(String(url));
      seenMethod = init?.method;
      const headers = (init?.headers ?? {}) as Record<string, string>;
      seenContentType = headers['Content-Type'] ?? null;
      const body = init?.body as Uint8Array | undefined;
      seenBodyBytes = body?.byteLength ?? 0;
      return new Response(
        JSON.stringify({ shadow_mode: true, fully_resolved: false, ack: true }),
        { status: 200 },
      );
    };

    await dispatcher.dispatchSeedHttp(
      basicFrameOpts(),
      fetchImpl as unknown as typeof fetch,
    );

    expect(seenUrls).toEqual(['https://test-worker.example.com/residual-seed']);
    expect(seenMethod).toBe('POST');
    expect(seenContentType).toBe('application/octet-stream');
    // 10-byte FlowCodec header + 8-byte payload prefix + 4 floats × 4 bytes.
    expect(seenBodyBytes).toBe(10 + 8 + 16);
  });

  it('passes Authorization header from initOverrides through to fetch', async () => {
    const dispatcher = makeDispatcher();
    let seenAuth: string | null = null;

    const fetchImpl = async (_url: RequestInfo | URL, init?: RequestInit) => {
      const headers = (init?.headers ?? {}) as Record<string, string>;
      seenAuth = headers['Authorization'] ?? null;
      return new Response(
        JSON.stringify({ shadow_mode: false, fully_resolved: true, ack: true }),
        { status: 200 },
      );
    };

    await dispatcher.dispatchSeedHttp(
      basicFrameOpts(),
      fetchImpl as unknown as typeof fetch,
      { headers: { Authorization: 'Bearer mesh-bench' } },
    );

    expect(seenAuth).toBe('Bearer mesh-bench');
  });

  it('strips trailing slash from dstWorkerUrl when constructing the POST URL', async () => {
    const dispatcher = makeDispatcher();
    const seen: string[] = [];
    const fetchImpl = async (url: RequestInfo | URL) => {
      seen.push(String(url));
      return new Response(
        JSON.stringify({ shadow_mode: true, fully_resolved: false }),
        { status: 200 },
      );
    };
    const opts = { ...basicFrameOpts(), dstWorkerUrl: 'https://w.example.com/' };
    await dispatcher.dispatchSeedHttp(opts, fetchImpl as unknown as typeof fetch);
    expect(seen).toEqual(['https://w.example.com/residual-seed']);
  });
});
